-- ==================== BEST PRACTICES ====================

INSERT INTO knowledge (title, content, category, source, sourceType, tags) VALUES (
  'MOTHER Development Best Practices',
  'Best practices learned from MOTHER v7.0 development:

**1. Defensive Programming:**
- Always use ?? 0 for numeric defaults
- Optional chaining for nested objects (usage?.total_tokens)
- Validate inputs before database operations
- Handle undefined gracefully

**2. Async Operations:**
- Fire-and-forget for non-critical operations (logging)
- Don\'t block user responses on metrics
- Use Promise.all() for parallel operations
- Implement retry logic with exponential backoff

**3. Database Operations:**
- Use retry logic (3 attempts, 1s/2s/4s delays)
- Async logging to prevent blocking
- Transaction management for critical operations
- Index frequently queried columns

**4. Testing Strategy:**
- Unit tests for each layer (14 tests)
- Integration tests for full flow (audit tests)
- GCloud production testing (real environment)
- Retry logic in tests for intermittent failures

**5. Error Handling:**
- Log errors but don\'t crash
- Return default values on failure
- Provide context in error messages
- Track error rates in metrics

**6. Cost Optimization:**
- Cache aggressively (30% hit rate target)
- Route intelligently (multi-tier)
- Compress prompts (Phase 2)
- Monitor costs continuously

**7. Quality Assurance:**
- Guardian layer for all responses
- Quality threshold enforcement (90/100)
- Continuous monitoring of quality scores
- A/B testing for improvements',
  'Best Practices',
  'MOTHER Engineering Guide',
  'learning',
  '["best-practices", "engineering", "development"]'
);

